import{_ as e,o as a,c as o,ag as d}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"System Settings","description":"","frontmatter":{},"headers":[],"relativePath":"guide/system-settings.md","filePath":"guide/system-settings.md"}'),r={name:"guide/system-settings.md"};function n(s,t,i,l,c,h){return a(),o("div",null,[...t[0]||(t[0]=[d(`<h1 id="system-settings" tabindex="-1">System Settings <a class="header-anchor" href="#system-settings" aria-label="Permalink to &quot;System Settings&quot;">​</a></h1><p>The System Settings panel is the central control hub for GeniusHRM. It is accessible via <strong>Admin Panel → Settings</strong> or directly at <code>/admin/settings</code>. Only users with the <strong>Admin</strong> role can access this panel.</p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The settings panel is divided into clearly labelled tabs. Each tab groups related configuration options. Changes take effect immediately upon saving; some settings (such as mail configuration) can be tested directly from the panel.</p><hr><h2 id="general-tab" tabindex="-1">General Tab <a class="header-anchor" href="#general-tab" aria-label="Permalink to &quot;General Tab&quot;">​</a></h2><p>The General tab controls the visual identity and basic information of the application.</p><h3 id="fields" tabindex="-1">Fields <a class="header-anchor" href="#fields" aria-label="Permalink to &quot;Fields&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><strong>Application Name</strong></td><td>Displayed in the browser title bar and navigation header</td><td><code>GeniusHRM</code></td></tr><tr><td><strong>Application Logo</strong></td><td>Header logo (PNG or SVG, max 2 MB)</td><td><code>logo.svg</code></td></tr><tr><td><strong>Favicon</strong></td><td>Browser tab icon (ICO or PNG, 32×32 recommended)</td><td><code>favicon.ico</code></td></tr><tr><td><strong>Footer Text</strong></td><td>Text in the bottom footer of every page</td><td><code>© 2026 XGeniousLLC</code></td></tr><tr><td><strong>Login Background</strong></td><td>Full-screen background image on login page</td><td><code>login-bg.jpg</code></td></tr></tbody></table><h3 id="how-to-update-the-logo" tabindex="-1">How to Update the Logo <a class="header-anchor" href="#how-to-update-the-logo" aria-label="Permalink to &quot;How to Update the Logo&quot;">​</a></h3><ol><li>Navigate to <strong>Settings → General</strong></li><li>Click <strong>Browse</strong> or <strong>Choose File</strong> next to the Logo field</li><li>Select your image file (SVG recommended for crisp rendering at all sizes)</li><li>Click <strong>Save Settings</strong></li><li>Clear your browser cache to see the updated logo immediately</li></ol><hr><h2 id="email-smtp-tab" tabindex="-1">Email (SMTP) Tab <a class="header-anchor" href="#email-smtp-tab" aria-label="Permalink to &quot;Email (SMTP) Tab&quot;">​</a></h2><p>Configure the outgoing mail server used for all system-generated emails including password resets, leave notifications, payslip delivery, and system alerts.</p><h3 id="fields-1" tabindex="-1">Fields <a class="header-anchor" href="#fields-1" aria-label="Permalink to &quot;Fields&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Mail Driver</strong></td><td>Transport driver (<code>smtp</code>, <code>mailgun</code>, <code>ses</code>, <code>log</code>)</td></tr><tr><td><strong>Mail Host</strong></td><td>SMTP server hostname</td></tr><tr><td><strong>Mail Port</strong></td><td>SMTP port (typically 587 for TLS, 465 for SSL, 25 for unencrypted)</td></tr><tr><td><strong>Encryption</strong></td><td><code>tls</code>, <code>ssl</code>, or <code>none</code></td></tr><tr><td><strong>Mail Username</strong></td><td>SMTP authentication username</td></tr><tr><td><strong>Mail Password</strong></td><td>SMTP authentication password</td></tr><tr><td><strong>From Address</strong></td><td>The <code>From:</code> email address recipients see</td></tr><tr><td><strong>From Name</strong></td><td>The <code>From:</code> display name recipients see</td></tr></tbody></table><h3 id="test-email" tabindex="-1">Test Email <a class="header-anchor" href="#test-email" aria-label="Permalink to &quot;Test Email&quot;">​</a></h3><p>After saving your SMTP configuration, click <strong>Send Test Email</strong> and enter any valid email address. If delivery succeeds, you will see a green confirmation banner. If it fails, check the error message and review your credentials.</p><hr><h2 id="sms-tab" tabindex="-1">SMS Tab <a class="header-anchor" href="#sms-tab" aria-label="Permalink to &quot;SMS Tab&quot;">​</a></h2><p>SMS notifications are used for leave approval alerts, onboarding messages, and optional OTP verification.</p><h3 id="fields-2" tabindex="-1">Fields <a class="header-anchor" href="#fields-2" aria-label="Permalink to &quot;Fields&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Enable SMS</strong></td><td>Toggle SMS functionality on or off</td></tr><tr><td><strong>SMS Provider</strong></td><td>Currently supports: <code>Twilio</code></td></tr><tr><td><strong>Account SID</strong></td><td>Twilio Account SID (<code>ACxxxxxxx</code>)</td></tr><tr><td><strong>Auth Token</strong></td><td>Twilio Auth Token</td></tr><tr><td><strong>From Number</strong></td><td>Twilio sender phone number in E.164 format (<code>+15551234567</code>)</td></tr></tbody></table><h3 id="test-sms" tabindex="-1">Test SMS <a class="header-anchor" href="#test-sms" aria-label="Permalink to &quot;Test SMS&quot;">​</a></h3><p>Enter a phone number in the test field and click <strong>Send Test SMS</strong>. Successful sends will be logged in <strong>Audit Log → SMS</strong>.</p><hr><h2 id="finance-tab" tabindex="-1">Finance Tab <a class="header-anchor" href="#finance-tab" aria-label="Permalink to &quot;Finance Tab&quot;">​</a></h2><p>Financial settings affect payroll calculations, payslip formatting, and financial reports.</p><h3 id="fields-3" tabindex="-1">Fields <a class="header-anchor" href="#fields-3" aria-label="Permalink to &quot;Fields&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Currency Code</strong></td><td>ISO 4217 code (e.g., <code>USD</code>, <code>GBP</code>, <code>BDT</code>)</td></tr><tr><td><strong>Currency Symbol</strong></td><td>Display symbol (e.g., <code>$</code>, <code>£</code>, <code>৳</code>)</td></tr><tr><td><strong>Symbol Position</strong></td><td><code>Before</code> (e.g., <code>$1,000</code>) or <code>After</code> (e.g., <code>1,000$</code>)</td></tr><tr><td><strong>Decimal Places</strong></td><td>Number of decimal digits (typically <code>2</code>)</td></tr><tr><td><strong>Decimal Separator</strong></td><td><code>.</code> (period) for most locales, <code>,</code> (comma) for European locales</td></tr><tr><td><strong>Thousands Separator</strong></td><td><code>,</code> (comma) for most locales, <code>.</code> (period) for European locales</td></tr><tr><td><strong>Financial Year Start Month</strong></td><td>Month when the fiscal year begins (1–12)</td></tr><tr><td><strong>Financial Year Start Day</strong></td><td>Day of the month (usually <code>1</code>)</td></tr></tbody></table><hr><h2 id="date-time-tab" tabindex="-1">Date &amp; Time Tab <a class="header-anchor" href="#date-time-tab" aria-label="Permalink to &quot;Date &amp; Time Tab&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Description</th><th>Options</th></tr></thead><tbody><tr><td><strong>Timezone</strong></td><td>Application timezone</td><td>Any valid PHP timezone (e.g., <code>UTC</code>, <code>Asia/Dhaka</code>)</td></tr><tr><td><strong>Date Format</strong></td><td>Date display format</td><td><code>Y-m-d</code>, <code>d/m/Y</code>, <code>m/d/Y</code>, <code>d-m-Y</code></td></tr><tr><td><strong>Time Format</strong></td><td>Time display format</td><td><code>H:i</code> (24h), <code>h:i A</code> (12h)</td></tr><tr><td><strong>Week Starts On</strong></td><td>First day of the week in calendars</td><td><code>Monday</code>, <code>Sunday</code>, <code>Saturday</code></td></tr></tbody></table><hr><h2 id="appearance-tab" tabindex="-1">Appearance Tab <a class="header-anchor" href="#appearance-tab" aria-label="Permalink to &quot;Appearance Tab&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Primary Colour</strong></td><td>Main brand colour used for buttons and accents (hex code)</td></tr><tr><td><strong>Sidebar Style</strong></td><td><code>Light</code> or <code>Dark</code> sidebar variant</td></tr><tr><td><strong>Default Language</strong></td><td>Application locale (e.g., <code>en</code>, <code>fr</code>, <code>ar</code>)</td></tr></tbody></table><hr><h2 id="module-settings" tabindex="-1">Module Settings <a class="header-anchor" href="#module-settings" aria-label="Permalink to &quot;Module Settings&quot;">​</a></h2><p>Some modules expose their own sub-settings within the Settings panel:</p><table tabindex="0"><thead><tr><th>Module</th><th>Setting Location</th></tr></thead><tbody><tr><td><strong>Leave</strong></td><td><code>/admin/settings/leave</code> — Configure leave reset date</td></tr><tr><td><strong>Payroll</strong></td><td><code>/admin/settings/payroll</code> — Default payroll cycle day</td></tr><tr><td><strong>Attendance</strong></td><td><code>/admin/settings/attendance</code> — Late threshold (minutes)</td></tr><tr><td><strong>Performance</strong></td><td><code>/admin/settings/performance</code> — Rating labels and thresholds</td></tr></tbody></table><hr><h2 id="saving-and-applying-changes" tabindex="-1">Saving and Applying Changes <a class="header-anchor" href="#saving-and-applying-changes" aria-label="Permalink to &quot;Saving and Applying Changes&quot;">​</a></h2><p>After editing any tab:</p><ol><li>Click <strong>Save Settings</strong> (bottom of the tab)</li><li>A success toast notification confirms the save</li><li>For settings that affect cached values (timezone, date format), run:</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config:clear</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cache:clear</span></span></code></pre></div><p>Or use the <strong>Clear Cache</strong> button in the General tab.</p>`,47)])])}const m=e(r,[["render",n]]);export{p as __pageData,m as default};
